   137	func (index *CheckIDIndex) FromObject(obj interface{}) (bool, []byte, error) {
   138		v := reflect.ValueOf(obj)
   139		v = reflect.Indirect(v) // Dereference the pointer if any
   140	
   141		fv := v.FieldByName("CheckID")
   142		isPtr := fv.Kind() == reflect.Ptr
   143		fv = reflect.Indirect(fv)
   144		if !isPtr && !fv.IsValid() || !fv.CanInterface() {
   145			return false, nil,
   146				fmt.Errorf("field 'EnterpriseMeta' for %#v is invalid %v ", obj, isPtr)
   147		}
   148	
   149		checkID, ok := fv.Interface().(structs.CheckID)
   150		if !ok {
   151			return false, nil, fmt.Errorf("Field 'EnterpriseMeta' is not of type structs.EnterpriseMeta")
   152		}
   153	
   154		// Enforce lowercase and add null character as terminator
   155		id := strings.ToLower(string(checkID.ID)) + "\x00"
   156	
   157		return true, []byte(id), nil
   158	}
