   160	func (index *CheckIDIndex) FromArgs(args ...interface{}) ([]byte, error) {
   161		if len(args) != 1 {
   162			return nil, fmt.Errorf("must provide only a single argument")
   163		}
   164		arg, ok := args[0].(string)
   165		if !ok {
   166			return nil, fmt.Errorf("argument must be a string: %#v", args[0])
   167		}
   168	
   169		arg = strings.ToLower(arg)
   170	
   171		// Add the null character as a terminator
   172		arg += "\x00"
   173		return []byte(arg), nil
   174	}
