   176	func (index *CheckIDIndex) PrefixFromArgs(args ...interface{}) ([]byte, error) {
   177		val, err := index.FromArgs(args...)
   178		if err != nil {
   179			return nil, err
   180		}
   181	
   182		// Strip the null terminator, the rest is a prefix
   183		n := len(val)
   184		if n > 0 {
