   209	// SessionCreate is used to register a new session in the state store.
   210	func (s *Store) SessionCreate(idx uint64, sess *structs.Session) error {
   211		tx := s.db.WriteTxn(idx)
   212		defer tx.Abort()
   213	
   214		// This code is technically able to (incorrectly) update an existing
   215		// session but we never do that in practice. The upstream endpoint code
   216		// always adds a unique ID when doing a create operation so we never hit
   217		// an existing session again. It isn't worth the overhead to verify
   218		// that here, but it's worth noting that we should never do this in the
   219		// future.
   220	
   221		// Call the session creation
   222		if err := sessionCreateTxn(tx, idx, sess); err != nil {
   223			return err
   224		}
   225	
   226		return tx.Commit()
   227	}
