   229	// sessionCreateTxn is the inner method used for creating session entries in
   230	// an open transaction. Any health checks registered with the session will be
   231	// checked for failing status. Returns any error encountered.
   232	func sessionCreateTxn(tx WriteTxn, idx uint64, sess *structs.Session) error {
   233		// Check that we have a session ID
   234		if sess.ID == "" {
   235			return ErrMissingSessionID
   236		}
   237	
   238		// Verify the session behavior is valid
   239		switch sess.Behavior {
   240		case "":
   241			// Release by default to preserve backwards compatibility
   242			sess.Behavior = structs.SessionKeysRelease
   243		case structs.SessionKeysRelease:
   244		case structs.SessionKeysDelete:
   245		default:
   246			return fmt.Errorf("Invalid session behavior: %s", sess.Behavior)
   247		}
   248	
   249		// Assign the indexes. ModifyIndex likely will not be used but
   250		// we set it here anyways for sanity.
   251		sess.CreateIndex = idx
   252		sess.ModifyIndex = idx
   253	
   254		// Check that the node exists
   255		node, err := tx.First(tableNodes, indexID, Query{Value: sess.Node, EnterpriseMeta: *structs.DefaultEnterpriseMetaInPartition(sess.PartitionOrDefault())})
   256		if err != nil {
   257			return fmt.Errorf("failed node lookup: %s", err)
   258		}
   259		if node == nil {
   260			return ErrMissingNode
   261		}
   262	
   263		// Verify that all session checks exist
   264		if err := validateSessionChecksTxn(tx, sess); err != nil {
   265			return err
   266		}
   267	
   268		// Insert the session
   269		if err := insertSessionTxn(tx, sess, idx, false, false); err != nil {
   270			return fmt.Errorf("failed inserting session: %s", err)
   271		}
   272	
   273		return nil
   274	}
