   276	// SessionGet is used to retrieve an active session from the state store.
   277	func (s *Store) SessionGet(ws memdb.WatchSet,
   278		sessionID string, entMeta *acl.EnterpriseMeta) (uint64, *structs.Session, error) {
   279	
   280		tx := s.db.Txn(false)
   281		defer tx.Abort()
   282	
   283		idx := maxIndexTxnSessions(tx, entMeta)
   284	
   285		// Look up the session by its ID
   286		if entMeta == nil {
   287			entMeta = structs.DefaultEnterpriseMetaInDefaultPartition()
   288		}
   289		watchCh, session, err := tx.FirstWatch(tableSessions, indexID, Query{Value: sessionID, EnterpriseMeta: *entMeta})
   290	
   291		if err != nil {
   292			return 0, nil, fmt.Errorf("failed session lookup: %s", err)
   293		}
   294		ws.Add(watchCh)
   295	
   296		if session != nil {
   297			return idx, session.(*structs.Session), nil
   298		}
   299		return idx, nil, nil
   300	}
