   320	// SessionDestroy is used to remove an active session. This will
   321	// implicitly invalidate the session and invoke the specified
   322	// session destroy behavior.
   323	func (s *Store) SessionDestroy(idx uint64, sessionID string, entMeta *acl.EnterpriseMeta) error {
   324		tx := s.db.WriteTxn(idx)
   325		defer tx.Abort()
   326	
   327		// Call the session deletion.
   328		if err := s.deleteSessionTxn(tx, idx, sessionID, entMeta); err != nil {
   329			return err
   330		}
   331	
   332		return tx.Commit()
   333	}
   334	
   335	// deleteSessionTxn is the inner method, which is used to do the actual
   336	// session deletion and handle session invalidation, etc.
   337	func (s *Store) deleteSessionTxn(tx WriteTxn, idx uint64, sessionID string, entMeta *acl.EnterpriseMeta) error {
   338		// Look up the session.
   339		if entMeta == nil {
   340			entMeta = structs.DefaultEnterpriseMetaInDefaultPartition()
   341		}
   342		sess, err := tx.First(tableSessions, indexID, Query{Value: sessionID, EnterpriseMeta: *entMeta})
   343		if err != nil {
   344			return fmt.Errorf("failed session lookup: %s", err)
   345		}
   346		if sess == nil {
   347			return nil
   348		}
   349	
   350		// Delete the session and write the new index.
   351		session := sess.(*structs.Session)
   352		if err := sessionDeleteWithSession(tx, session, idx); err != nil {
   353			return fmt.Errorf("failed deleting session: %v", err)
   354		}
   355	
   356		// Enforce the max lock delay.
   357		delay := session.LockDelay
   358		if delay > structs.MaxLockDelay {
   359			delay = structs.MaxLockDelay
   360		}
   361	
   362		// Snag the current now time so that all the expirations get calculated
   363		// the same way.
   364		now := time.Now()
   365	
   366		// Get an iterator over all of the keys with the given session.
   367		entries, err := tx.Get(tableKVs, indexSession, sessionID)
   368		if err != nil {
   369			return fmt.Errorf("failed kvs lookup: %s", err)
   370		}
   371		var kvs []interface{}
   372		for entry := entries.Next(); entry != nil; entry = entries.Next() {
   373			kvs = append(kvs, entry)
   374		}
   375	
   376		// Invalidate any held locks.
   377		switch session.Behavior {
   378		case structs.SessionKeysRelease:
   379			for _, obj := range kvs {
   380				// Note that we clone here since we are modifying the
   381				// returned object and want to make sure our set op
   382				// respects the transaction we are in.
   383				e := obj.(*structs.DirEntry).Clone()
   384				e.Session = ""
   385				if err := kvsSetTxn(tx, idx, e, true); err != nil {
   386					return fmt.Errorf("failed kvs update: %s", err)
   387				}
   388	
   389				// Apply the lock delay if present.
   390				if delay > 0 {
   391					s.lockDelay.SetExpiration(e.Key, now, delay, entMeta)
   392				}
   393			}
   394		case structs.SessionKeysDelete:
   395			for _, obj := range kvs {
   396				e := obj.(*structs.DirEntry)
   397				if err := s.kvsDeleteTxn(tx, idx, e.Key, entMeta); err != nil {
   398					return fmt.Errorf("failed kvs delete: %s", err)
   399				}
   400	
   401				// Apply the lock delay if present.
   402				if delay > 0 {
   403					s.lockDelay.SetExpiration(e.Key, now, delay, entMeta)
   404				}
   405			}
   406		default:
   407			return fmt.Errorf("unknown session behavior %#v", session.Behavior)
   408		}
   409	
   410		if entMeta == nil {
   411			entMeta = structs.DefaultEnterpriseMetaInDefaultPartition()
   412		}
   413		// Delete any check mappings.
   414		mappings, err := tx.Get(tableSessionChecks, indexSession, Query{Value: sessionID, EnterpriseMeta: *entMeta})
   415		if err != nil {
   416			return fmt.Errorf("failed session checks lookup: %s", err)
   417		}
   418		{
   419			var objs []interface{}
   420			for mapping := mappings.Next(); mapping != nil; mapping = mappings.Next() {
   421				objs = append(objs, mapping)
   422			}
   423	
   424			// Do the delete in a separate loop so we don't trash the iterator.
   425			for _, obj := range objs {
   426				if err := tx.Delete(tableSessionChecks, obj); err != nil {
   427					return fmt.Errorf("failed deleting session check: %s", err)
   428				}
   429			}
   430		}
   431	
   432		// Delete any prepared queries.
   433		queries, err := tx.Get("prepared-queries", "session", sessionID)
   434		if err != nil {
   435			return fmt.Errorf("failed prepared query lookup: %s", err)
   436		}
   437		{
   438			var ids []string
   439			for wrapped := queries.Next(); wrapped != nil; wrapped = queries.Next() {
   440				ids = append(ids, toPreparedQuery(wrapped).ID)
   441			}
   442	
   443			// Do the delete in a separate loop so we don't trash the iterator.
   444			for _, id := range ids {
   445				if err := preparedQueryDeleteTxn(tx, idx, id); err != nil {
   446					return fmt.Errorf("failed prepared query delete: %s", err)
   447				}
   448			}
   449		}
   450	
   451		return nil
   452	}
