		hc := check.(*structs.HealthCheck)
		// Verify that the check is not in critical state
		// Session type checks are allowed to be in critical state since they
		// are expected to be critical before the session exists
		status := hc.Status
		if status == api.HealthCritical && hc.Type != "session" {
			return fmt.Errorf("Check '%s' is in %s state", checkID, status)
		}
	}
	return nil
}

