func TestStateStore_Session_HealthCheckUpdate(t *testing.T) {
	s := testStateStore(t)

	// Register a node
	testRegisterNode(t, s, 1, "node1")

	// Register a session-type health check that references a session name
	sessionName := "my-session"
	check := &structs.HealthCheck{
		Node:    "node1",
		CheckID: "session-check-1",
		Name:    "Session Check",
		Type:    "session",
		Status:  api.HealthCritical, // Starts critical
		Output:  "Waiting for session",
		Definition: structs.HealthCheckDefinition{
			SessionName: sessionName,
		},
	}
	if err := s.EnsureCheck(2, check); err != nil {
		t.Fatalf("err: %s", err)
	}

	// Verify the check is critical
	_, checks, err := s.NodeChecks(nil, "node1", nil, "")
	if err != nil {
		t.Fatalf("err: %s", err)
	}
	if len(checks) != 1 {
		t.Fatalf("expected 1 check, got %d", len(checks))
	}
	if checks[0].Status != api.HealthCritical {
		t.Fatalf("expected check to be critical, got %s", checks[0].Status)
	}

	// Create a session with matching Name
	sess := &structs.Session{
		ID:   testUUID(),
		Node: "node1",
		Name: sessionName,
	}
	if err := s.SessionCreate(3, sess); err != nil {
		t.Fatalf("err: %s", err)
	}

	// Verify the check is now passing
	_, checks, err = s.NodeChecks(nil, "node1", nil, "")
	if err != nil {
		t.Fatalf("err: %s", err)
	}
	if len(checks) != 1 {
		t.Fatalf("expected 1 check, got %d", len(checks))
	}
	if checks[0].Status != api.HealthPassing {
		t.Fatalf("expected check to be passing after session create, got %s", checks[0].Status)
	}
	expectedOutput := "Session '" + sess.ID + "' in force"
	if checks[0].Output != expectedOutput {
		t.Fatalf("expected output %q, got %q", expectedOutput, checks[0].Output)
	}

	// Destroy the session
	if err := s.SessionDestroy(4, sess.ID, nil); err != nil {
		t.Fatalf("err: %s", err)
	}

	// Verify the check is now critical
	_, checks, err = s.NodeChecks(nil, "node1", nil, "")
	if err != nil {
		t.Fatalf("err: %s", err)
	}
	if len(checks) != 1 {
		t.Fatalf("expected 1 check, got %d", len(checks))
	}
	if checks[0].Status != api.HealthCritical {
		t.Fatalf("expected check to be critical after session destroy, got %s", checks[0].Status)
	}
	expectedOutput = "Session '" + sess.ID + "' is invalid"
	if checks[0].Output != expectedOutput {
		t.Fatalf("expected output %q, got %q", expectedOutput, checks[0].Output)
	}
}

