+// updateSessionHealthChecks finds all health checks on the same node with Type="session"
+// and Definition.SessionName matching the session's Name, and updates their status.
+func updateSessionHealthChecks(tx WriteTxn, idx uint64, session *structs.Session, status string, output string) error {
+	// Get all checks for this node
+	iter, err := catalogListChecksByNode(tx, Query{Value: session.Node})
+	if err != nil {
+		return fmt.Errorf("failed check lookup: %s", err)
+	}
+
+	var checksToUpdate []*structs.HealthCheck
+	for check := iter.Next(); check != nil; check = iter.Next() {
+		hc := check.(*structs.HealthCheck)
+		// Only update checks that are session type and match the session name
+		if hc.Type == "session" && hc.Definition.SessionName == session.Name {
+			checksToUpdate = append(checksToUpdate, hc)
+		}
+	}
+
+	// Update each matching check
+	for _, hc := range checksToUpdate {
+		// Clone the check to avoid modifying the original in-place
+		updated := hc.Clone()
+		updated.Status = status
+		updated.Output = output
+		updated.ModifyIndex = idx
+
+		if err := catalogInsertCheck(tx, updated, idx); err != nil {
+			return fmt.Errorf("failed updating check %s: %s", hc.CheckID, err)
+		}
+	}
+
